let selectedOfficeCode='';

function allOffices(){
  return Object.values(window.FPL_CONTACTS || {})
    .sort((a,b)=>a.code.localeCompare(b.code));
}

function officeSearchText(office){
  return [
    office.code, office.city, office.airport, office.department,
    office.regional, office.aliases, office.searchKey
  ].join(' ').toUpperCase();
}

function findOfficeByCode(code){
  return window.FPL_CONTACTS?.[normalizeCode(code,4)] || null;
}

function selectedOffice(){
  return selectedOfficeCode ? window.FPL_CONTACTS?.[selectedOfficeCode] || null : null;
}

function communicationOffice(office){
  if(!office) return null;
  const receiver=office.receiverCode ? window.FPL_CONTACTS?.[office.receiverCode] : null;
  return {
    ...office,
    communicationCode:office.receiverCode || office.code,
    communicationName:receiver?.airport || office.airport,
    fpl:office.receiverFpl || office.fpl || receiver?.fpl || '',
    email:office.receiverEmail || office.email || receiver?.email || ''
  };
}

function renderSelectedOffice(){
  const office=selectedOffice();
  const box=$('selectedOffice');
  if(!office){
    box.innerHTML='No ha seleccionado una oficina.';
    $('callBtn').disabled=true;
    $('copyEmailBtn').disabled=true;
    $('emailBtn').disabled=true;
    return;
  }

  const contact=communicationOffice(office);
  const warning=office.status && !office.status.toLowerCase().includes('completo')
    ? `<span class="office-warning">${office.status}</span>` : '';

  box.innerHTML=`<strong>${office.code} · ${office.city} / ${office.airport}</strong>
    Regional: ${office.regional || 'No registrada'}<br>
    Torre: ${office.tower || 'No registrado'}<br>
    Oficina receptora: ${contact.communicationCode}${contact.communicationCode!==office.code ? ` · ${contact.communicationName}` : ''}<br>
    Plan de vuelo: ${contact.fpl || 'No registrado'}<br>
    Correo: ${contact.email || 'No registrado'}<br>
    ${office.note ? `<span class="office-warning">${office.note}</span>` : warning}`;

  $('callBtn').disabled=!(contact.fpl || office.tower);
  $('copyEmailBtn').disabled=!contact.email;
  $('emailBtn').disabled=!contact.email;
}

function selectOffice(code){
  const office=findOfficeByCode(code);
  if(!office) return;
  selectedOfficeCode=office.code;
  $('recipientSearch').value=`${office.code} - ${office.city}`;
  $('recipientSuggestions').classList.add('hidden');
  renderSelectedOffice();
}

function renderRecipientSuggestions(){
  const query=upperTyping($('recipientSearch').value).trim();
  const box=$('recipientSuggestions');
  if(!query){
    box.classList.add('hidden');
    box.innerHTML='';
    return;
  }
  const matches=allOffices()
    .filter(office=>officeSearchText(office).includes(query))
    .slice(0,12);

  if(!matches.length){
    box.innerHTML='<div class="directory-empty">No se encontró ese aeródromo.</div>';
    box.classList.remove('hidden');
    return;
  }

  box.innerHTML=matches.map(office=>`
    <button type="button" class="recipient-option" data-office-code="${office.code}">
      <strong>${office.code} · ${office.city}</strong>
      <small>${office.airport} · ${office.regional}</small>
    </button>`).join('');
  box.classList.remove('hidden');
}

$('recipientSearch').addEventListener('input',event=>{
  event.target.value=upperTyping(event.target.value);
  selectedOfficeCode='';
  renderSelectedOffice();
  renderRecipientSuggestions();
});

$('recipientSuggestions').addEventListener('click',event=>{
  const button=event.target.closest('[data-office-code]');
  if(button) selectOffice(button.dataset.officeCode);
});

$('selectFromDepartureBtn').addEventListener('click',()=>{
  const office=findOfficeByCode($('departure').value);
  if(!office){
    alert('No hay una oficina registrada para el código de salida ingresado.');
    return;
  }
  selectOffice(office.code);
});

$('callBtn').addEventListener('click',()=>{
  const office=selectedOffice();
  if(!office) return;
  const contact=communicationOffice(office);
  const number=contact.fpl || office.tower;
  if(number) window.location.href=`tel:${number}`;
});

$('copyEmailBtn').addEventListener('click',async()=>{
  const office=selectedOffice();
  const contact=communicationOffice(office);
  if(!contact?.email) return;
  try{
    await navigator.clipboard.writeText(contact.email);
    toast('Correo copiado');
  }catch{
    window.prompt('Copie el correo:',contact.email);
  }
});

window.addEventListener('beforeinstallprompt',e=>{
  e.preventDefault();deferredPrompt=e;$('installBtn').classList.remove('hidden');
});
$('installBtn').addEventListener('click',async()=>{
  if(!deferredPrompt)return; deferredPrompt.prompt(); await deferredPrompt.userChoice; deferredPrompt=null;
  $('installBtn').classList.add('hidden');
});
let waitingServiceWorker=null;
let serviceWorkerRegistration=null;

function showUpdateBanner(worker){
  waitingServiceWorker=worker;
  $('updateBanner')?.classList.remove('hidden');
}

$('updateNowBtn')?.addEventListener('click',()=>{
  if(waitingServiceWorker){
    waitingServiceWorker.postMessage({type:'SKIP_WAITING'});
  }else{
    window.location.reload();
  }
});


async function checkForUpdates(){
  const status=$('updateStatus');
  try{
    status.textContent='Verificando actualización…';
    if(!('serviceWorker' in navigator)){
      status.textContent='Este navegador no admite actualizaciones automáticas.';
      return;
    }

    const registration=serviceWorkerRegistration || await navigator.serviceWorker.getRegistration();
    if(!registration){
      status.textContent='No se encontró el servicio de actualización. Pulse “Recargar aplicación”.';
      return;
    }

    serviceWorkerRegistration=registration;
    await registration.update();
    await new Promise(resolve=>setTimeout(resolve,2200));

    if(registration.waiting){
      showUpdateBanner(registration.waiting);
      status.textContent='Hay una actualización disponible. Pulse “Actualizar ahora” en la franja superior.';
    }else if(registration.installing){
      status.textContent='La actualización se está descargando. Espere unos segundos.';
    }else{
      status.textContent=`La aplicación está actualizada. Versión instalada: ${APP_VERSION}`;
    }
  }catch(error){
    console.error(error);
    status.textContent='No se pudo verificar. Revise la conexión y vuelva a intentarlo.';
  }
}

$('checkUpdateBtn')?.addEventListener('click',checkForUpdates);
$('headerUpdateBtn')?.addEventListener('click',()=>{
  switchTab('updates');
  checkForUpdates();
});
$('forceReloadBtn')?.addEventListener('click',async()=>{
  try{
    const keys=await caches.keys();
    await Promise.all(keys.map(key=>caches.delete(key)));
  }catch{}
  window.location.reload(true);
});

// Versión 3.0.6: el Service Worker queda desactivado temporalmente.
// Esto evita que iPhone/Mac conserven archivos de versiones anteriores.
if ('serviceWorker' in navigator) {
  navigator.serviceWorker.getRegistrations()
    .then(registrations => Promise.all(registrations.map(registration => registration.unregister())))
    .catch(() => {});
}



$('companyLogoInput')?.addEventListener('change',event=>{
  const file=event.target.files?.[0];
  if(!file) return;
  if(file.size>900000){
    alert('El logo debe pesar menos de 900 KB.');
    event.target.value='';
    return;
  }
  const reader=new FileReader();
  reader.onload=()=>{
    const settings=getSettings();
    settings.companyLogo=String(reader.result || '');
    saveSettings(settings);
    updateProfileLogoPreview(settings.companyLogo);
    toast('Logo guardado');
  };
  reader.readAsDataURL(file);
});

$('removeLogoBtn')?.addEventListener('click',()=>{
  const settings=getSettings();
  settings.companyLogo='';
  saveSettings(settings);
  $('companyLogoInput').value='';
  updateProfileLogoPreview('');
  toast('Logo eliminado');
});

